SELECT category_name
FROM indicator_categories
WHERE category_id BETWEEN 10 AND 20;

SELECT MAX(value) AS second_highest_value
FROM (
    SELECT value
    FROM indicator_values
    WHERE value < (SELECT MAX(value) FROM indicator_values)
);

SELECT user_name, email
FROM users
WHERE user_id IN (
    SELECT user_id
    FROM access_logs
    WHERE indicator_id IN (
        SELECT indicator_id
        FROM economic_indicators
    )
) AND role = 'economist';

SELECT indicator_id, year_quarter_id, region_id, sector_id, category_id
FROM economic_indicators
WHERE region_id = 1;

SELECT COUNT(*) 
FROM economic_indicators ei
WHERE ei.sector_id = (SELECT sector_id FROM sectors WHERE sector_name = 'Manufacturing');

SELECT user_id
FROM users
WHERE role = 'economist';

SELECT iv.indicator_id, it.type_name, iv.value, iv.created_at
FROM indicator_values iv
JOIN indicator_types it ON iv.type_id = it.type_id;

SELECT role_name 
FROM roles 
WHERE role_id IN (
    SELECT role_id 
    FROM user_roles
);
